   173→class ThreadLocalStreamManager : public Envoy::ThreadLocal::ThreadLocalObject {
   174→public:
   175→  // Store the ExternalProcessorStreamPtr (as a wrapper object) in the map and return the raw
   176→  // pointer of ExternalProcessorStream.
   177→  ExternalProcessorStream* store(uint64_t stream_id, ExternalProcessorStreamPtr stream,
   178→                                 const ExtProcFilterStats& stat,
   179→                                 const std::chrono::milliseconds& timeout) {
   180→    stream_manager_[stream_id] =
   181→        std::make_unique<DeferredDeletableStream>(std::move(stream), *this, stat, timeout);
