   226→void ExtProcLoggingInfo::recordGrpcCall(
   227→    std::chrono::microseconds latency, Grpc::Status::GrpcStatus call_status,
   228→    ProcessorState::CallbackState callback_state,
   229→    envoy::config::core::v3::TrafficDirection traffic_direction) {
